const express = require('express');
const fs = require('fs');
const path = require('path');
require('dotenv').config();

const app = express();
const PORT = process.env.PORT || 8080;
const TOKEN = process.env.ACESSO_TOKEN;

// Arquivo de log
const LOG_FILE = path.join(__dirname, 'access-log.json');

// ============================================
// MIDDLEWARE: Rastreamento de Acessos
// ============================================
const logAcesso = (req, res, next) => {
  const log = {
    timestamp: new Date().toISOString(),
    metodo: req.method,
    caminho: req.path,
    ip: req.ip,
    userAgent: req.get('user-agent'),
    autenticado: !!req.autenticado
  };

  // Log em arquivo
  let logs = [];
  if (fs.existsSync(LOG_FILE)) {
    logs = JSON.parse(fs.readFileSync(LOG_FILE, 'utf-8'));
  }
  logs.push(log);

  // Manter apenas últimos 1000 acessos
  if (logs.length > 1000) logs.shift();

  fs.writeFileSync(LOG_FILE, JSON.stringify(logs, null, 2));
  next();
};

// ============================================
// MIDDLEWARE: Autenticação
// ============================================
const autenticacao = (req, res, next) => {
  const token = req.query.token || req.get('authorization')?.split(' ')[1];

  if (!token || token !== TOKEN) {
    // Sem token: mostrar página de login
    res.writeHead(401, { 'Content-Type': 'text/html; charset=utf-8' });
    res.end(getPaginaLogin());
    return;
  }

  req.autenticado = true;
  next();
};

