        </div>
        <form method="GET" action="">
          <input
            type="password"
            name="token"
            placeholder="Digite o token de acesso"
            required
            autofocus
          >
          <button type="submit">Acessar</button>
        </form>
        <div class="footer">
          Acesso registrado para auditoria
