// Servir HTMLs protegidos
app.get('/:arquivo.html', autenticacao, (req, res) => {
  const arquivo = req.params.arquivo;
  const filePath = path.join(__dirname, `${arquivo}.html`);

  // Segurança: evitar path traversal
  if (!filePath.startsWith(__dirname)) {
    res.status(403).send('Forbidden');
    return;
  }

  fs.readFile(filePath, (err, data) => {
    if (err) {
      res.status(404).send('<h1>Arquivo não encontrado</h1>');
    } else {
      res.setHeader('Content-Type', 'text/html; charset=utf-8');
      // Adicionar cabeçalho de segurança
      res.setHeader('X-Content-Type-Options', 'nosniff');
      res.setHeader('X-Frame-Options', 'SAMEORIGIN');
      res.send(data);
    }
  });
});

// Admin: Ver logs de acesso
app.get('/admin/logs', (req, res) => {
  const senha = req.query.senha || req.get('authorization')?.split(' ')[1];
  if (senha !== process.env.SENHA_ADMIN) {
    res.status(401).send('Não autorizado');
    return;
  }

  if (!fs.existsSync(LOG_FILE)) {
    res.json({ acessos: [] });
    return;
  }

  const logs = JSON.parse(fs.readFileSync(LOG_FILE, 'utf-8'));
  res.json({
    total: logs.length,
    ultimos: logs.slice(-50)
  });
});

